queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?role WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasAdditional_Roles ?child ; p:hasDirectors ?parent . } GROUP BY ?child }
  ?child p:Role ?role .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Directors } }
  FILTER(?nf = ?total)
}

